#!/usr/bin/env node

/**
 * Build the dedicated material parent page from every professional site's real
 * `lib/materials.ts`. The generated file is committed, so Vercel never needs
 * access to sibling repositories.
 */

import fs from "node:fs";
import path from "node:path";
import vm from "node:vm";
import ts from "typescript";

const projectsRoot = process.env.OCEANLEO_PROJECTS_ROOT || "/root/projects";
const catalogPath =
  process.env.OCEANLEO_SITES_TSV ||
  "/opt/cursor-workspaces/oceandino/scripts/oceanleo-sites.tsv";
const outputPath = path.resolve("lib/material-catalog.generated.ts");

const BOARDS_BY_SITE = {
  agent: ["website", "doc", "canvas"],
  website: ["website"],
  ecommerce: ["image", "poster", "design"],
  ppt: ["ppt", "slides"],
  excel: ["sheet"],
  word: ["doc"],
  converter: ["doc", "image"],
  aihuman: ["video", "video_canvas"],
  image: ["image", "poster", "xhs"],
  video: ["video", "video_canvas"],
  resume: ["doc"],
  bizdev: ["website", "doc"],
  logo: ["image", "design"],
  interior: ["image", "design", "threed"],
  chat: ["doc"],
  threed: ["threed"],
  music: ["audio"],
  meeting: ["doc"],
  paper: ["doc"],
  law: ["doc"],
  study: ["doc", "slides"],
  edu: ["doc", "slides"],
  novel: ["doc"],
  script: ["doc", "video"],
  design: ["image", "poster", "design", "canvas", "xhs"],
  make: ["canvas", "website"],
  search: ["website", "doc"],
  money: ["sheet"],
  aitools: ["website"],
  asset: ["image", "poster", "design"],
  game: ["canvas"],
};

function siteOrigin(key) {
  const host = key === "ppt" ? "slide" : key;
  return `https://${host}.oceanleo.com`;
}

function absoluteUrl(value, key) {
  if (typeof value !== "string" || !value) return value;
  if (value.startsWith("//")) return `https:${value}`;
  if (value.startsWith("/")) return `${siteOrigin(key)}${value}`;
  return value;
}

function loadMaterials(file) {
  const source = fs.readFileSync(file, "utf8");
  const js = ts.transpileModule(source, {
    compilerOptions: {
      module: ts.ModuleKind.CommonJS,
      target: ts.ScriptTarget.ES2020,
      esModuleInterop: true,
    },
    fileName: file,
  }).outputText;
  const module = { exports: {} };
  const context = {
    module,
    exports: module.exports,
    require: () => ({}),
    console: { warn() {}, log() {}, error() {} },
  };
  vm.runInNewContext(js, context, { filename: file, timeout: 1_000 });
  return Array.isArray(module.exports.MATERIALS)
    ? module.exports.MATERIALS
    : [];
}

const rows = fs
  .readFileSync(catalogPath, "utf8")
  .split(/\r?\n/)
  .filter((line) => line && !line.startsWith("#") && !line.startsWith("key\t"))
  .map((line) => {
    const [key, dir, frontend] = line.split("\t");
    return { key, dir, frontend };
  });

const itemById = {};
const canonicalToId = new Map();
const idsByBoard = {};
let boardLinks = 0;
for (const { key, dir, frontend } of rows) {
  const file = path.join(
    projectsRoot,
    dir,
    frontend === "." ? "" : frontend,
    "lib",
    "materials.ts",
  );
  if (!fs.existsSync(file)) continue;
  const materials = loadMaterials(file);
  const boards = BOARDS_BY_SITE[key] || [];
  for (const material of materials) {
    const thumb = absoluteUrl(material.thumb, key);
    const preview = absoluteUrl(material.preview, key);
    const openUrl = absoluteUrl(material.openUrl, key);
    const canonical = `${material.id}\u0000${thumb || ""}\u0000${openUrl || ""}`;
    let id = canonicalToId.get(canonical);
    if (!id) {
      id = `${key}--${material.id}`;
      canonicalToId.set(canonical, id);
      itemById[id] = {
        ...material,
        id,
        thumb,
        preview,
        openUrl,
        categories: Array.isArray(material.categories)
          ? [...material.categories]
          : [],
        tags: Array.isArray(material.tags) ? [...material.tags] : [],
      };
    }
    const item = itemById[id];
    if (!item.tags.includes(key)) item.tags.push(key);
    for (const board of boards) {
      const ids = (idsByBoard[board] ||= []);
      if (!ids.includes(id)) {
        ids.push(id);
        boardLinks += 1;
      }
    }
  }
}

const header = `// AUTO-GENERATED by scripts/gen-material-catalog.mjs — do not edit by hand.
// Sources: every OceanLeo professional site's committed lib/materials.ts.
import type { MaterialBoardId, MaterialItem } from "@oceanleo/ui/shell";

const MATERIAL_BY_ID: Record<string, MaterialItem> = `;
fs.writeFileSync(
  outputPath,
  `${header}${JSON.stringify(itemById, null, 2)};

const MATERIAL_IDS_BY_BOARD: Partial<Record<MaterialBoardId, string[]>> = ${JSON.stringify(idsByBoard, null, 2)};

export const MATERIALS_BY_BOARD: Partial<Record<MaterialBoardId, MaterialItem[]>> =
  Object.fromEntries(
    Object.entries(MATERIAL_IDS_BY_BOARD).map(([board, ids]) => [
      board,
      (ids ?? []).map((id) => MATERIAL_BY_ID[id]).filter(Boolean),
    ]),
  );
`,
);
console.log(
  `generated ${path.relative(process.cwd(), outputPath)} (${Object.keys(idsByBoard).length} boards, ${Object.keys(itemById).length} unique materials, ${boardLinks} board links)`,
);
